<div style="padding:8px;font-size:12px;opacity:.8" class="no-print">
  MARKER={{ marker }} | DEBUG url={{ debugUrl }} | id={{ debugId }} | count={{ debugCount }}
</div>

<div class="preview-toolbar no-print">
  <button class="btn ghost" (click)="back()">Retour</button>
  <div class="toolbar-actions">
    <button class="btn outline" (click)="edit()" [disabled]="!invoice">Modifier</button>
    <button class="btn primary" (click)="print()" [disabled]="!invoice">Imprimer</button>
    <button class="btn ghost" *ngIf="electron.isElectron" (click)="exportPdf()" [disabled]="!invoice">
      Exporter PDF
    </button>
  </div>
</div>

<div class="invoice-page" *ngIf="invoice as inv">
  <!-- ======= TOP HEADER (FR | LOGO | AR) ======= -->
  <header class="top-header">
    <div class="company-fr">
      <div class="line1">SOCIETE PRATIQUES ALUMINIUM</div>
      <div>59, Av. de l’Indépendance - Cité Ettadhamen</div>
      <div>2041 ARIANA</div>
    </div>

    <div class="top-logo">
      <img
        *ngIf="logoAvailable"
        src="assets/logospa.png"
        alt="SPA logo"
        (error)="logoAvailable = false"
      >
      <div *ngIf="!logoAvailable" class="logo-fallback">SPA</div>
    </div>

    <div class="company-ar" dir="rtl" lang="ar">
      <div class="line1">شركة تطبيقات الألومنيوم</div>
      <div>59، شارع الاستقلال - حي التضامن</div>
      <div>2041 أريانة</div>
    </div>
  </header>

  <!-- ======= CLIENT CENTER + DATE RIGHT ======= -->
  <section class="client-row">
    <div class="client-center">
  <div class="client-name">
    {{ inv.client.nom }}
  </div>

  <div class="client-sub">
    {{ inv.client.adresse }}
  </div>

  <div class="client-sub" *ngIf="inv.client.mf">
    CODE T.V.A : {{ inv.client.mf }}
  </div>
</div>


    <div class="date-right">
      <div class="muted">Tunis, le</div>
      <div class="date-strong">{{ inv.date | date:'dd/MM/yyyy' }}</div>
    </div>
  </section>

  <!-- ======= TITLE ======= -->
  <div class="invoice-title">
    FACTURE N° <span class="mono">{{ inv.numero }}</span>
  </div>

  <div class="order-line">
    Bon de Commande N° <span class="muted">—</span>
  </div>

  <!-- ======= TABLE ======= -->
  <table class="invoice-table">
    <thead>
      <tr>
        <th class="col-ord">ORD</th>
        <th>DESIGNATIONS</th>
        <th class="col-u">U</th>
        <th class="col-q">QUANT</th>
        <th class="col-pu">P.UNIT</th>
        <th class="col-pt">P.TOTAL</th>
      </tr>
    </thead>

    <tbody>
      <tr *ngFor="let line of inv.lignes; let i = index">
        <td class="center">{{ i + 1 }}</td>
        <td>{{ line.designation }}</td>
        <td class="center">{{ line.unite }}</td>
        <td class="center">{{ line.quantite | number:'1.0-3' }}</td>
        <td class="num">{{ line.prixUnitaire | number:'1.3-3' }}</td>
        <td class="num">{{ calc.lineHT(line) | number:'1.3-3' }}</td>
      </tr>
    </tbody>
  </table>

  <!-- ======= TOTALS RIGHT BOX ======= -->
  <div class="totals-area">
    <table class="totals">
      <tbody>
        <tr>
          <td>TOTAL Hors taxes</td>
          <td class="num">{{ (totals.totalHTApresRemise || totals.totalHT) | number:'1.3-3' }}</td>
        </tr>

        <tr *ngIf="totals.remise > 0">
          <td>Remise</td>
          <td class="num">- {{ totals.remise | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>Fodec (1%)</td>
          <td class="num">{{ totalsFinal.fodec | number:'1.3-3' }}</td>
        </tr>

